        content: "```csharp\n// Options pattern — configurare tipizata:\npublic class EmailOptions\n{\n    public string SmtpHost { get; set; } = string.Empty;\n    public int Port { get; set; } = 587;\n    public string From { get; set; } = string.Empty;\n}\n\n// appsettings.json:\n// { \"Email\": { \"SmtpHost\": \"smtp.gmail.com\", \"Port\": 587 } }\n\nbuilder.Services.Configure<EmailOptions>(\n    builder.Configuration.GetSection(\"Email\"));\n\n// Injectare cu IOptions<T>:\npublic class EmailService(IOptions<EmailOptions> options)\n{\n    private readonly EmailOptions _opt = options.Value;\n    // _opt.SmtpHost, _opt.Port, etc.\n}\n\n// Keyed services (NET 8+) — inregistrare dupa cheie:\nbuilder.Services.AddKeyedScoped<IStorage, LocalStorage>(\"local\");\nbuilder.Services.AddKeyedScoped<IStorage, CloudStorage>(\"cloud\");\n\n// Injectare keyed:\npublic class Controller([FromKeyedServices(\"cloud\")] IStorage storage) {}\n\n// Testabilitate — mock in unit tests:\nvar mockRepo = new Mock<IStudentRepository>();\nmockRepo.Setup(r => r.GetAllAsync())\n    .ReturnsAsync(new List<StudentDto>());\nvar service = new StudentService(mockRepo.Object, ...);\n```"
